module divide_by_8 (  
    input clk,  
    input rst,  
    output reg out  
);  
    reg [2:0] countdown;  // 3-bit countdown to count up to 7  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            countdown <= 3'b000;  
            out <= 0;  
        end else begin  
            if (countdown == 3'b111) begin  
                countdown <= 3'b000;  
                out <= ~out;  // toggle output  
            end else begin  
                countdown <= countdown + 1;  
            end  
        end  
    end  
endmodule
